import{_ as n,o as s,c as e,ag as t}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"自定义前端指南","description":"","frontmatter":{},"headers":[],"relativePath":"creator-guide/07-components.md","filePath":"creator-guide/07-components.md","lastUpdated":null}'),p={name:"creator-guide/07-components.md"};function o(l,a,i,d,r,c){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="自定义前端指南" tabindex="-1">自定义前端指南 <a class="header-anchor" href="#自定义前端指南" aria-label="Permalink to &quot;自定义前端指南&quot;">​</a></h1><blockquote><p>你的世界不需要看起来像一个聊天窗口。这篇教你怎么把它变成任何你想要的样子——而且不用自己写代码。</p></blockquote><hr><h2 id="简单版" tabindex="-1">简单版 <a class="header-anchor" href="#简单版" aria-label="Permalink to &quot;简单版&quot;">​</a></h2><p>Yumina 默认用普通文字显示 AI 的回复。但你可以自定义两样东西：</p><ul><li><strong>消息渲染器（messageRenderer）</strong>：改变每条 AI 消息的外观。让纯文字变成气泡对话、视觉小说、战斗日志……</li><li><strong>自定义组件（customComponents）</strong>：额外的 UI 面板。可以做角色创建界面、游戏侧边栏、全屏地图……</li></ul><p>这两个都需要 TSX 代码，但<strong>你不需要自己写</strong>。用 AI 来生成就好了：</p><ul><li><strong>内置方法</strong>：编辑器里点 <strong>进入 Studio（Enter Studio）</strong> → 打开 <strong>AI Assistant</strong> 面板 → 用中文告诉它你想要什么</li><li><strong>外部方法</strong>：把需求描述发给 Claude / ChatGPT / DeepSeek，让它写好代码，复制粘贴进来</li></ul><p>就这么简单。下面是详细说明 ᕕ( ᐛ )ᕗ</p><hr><h2 id="详细版" tabindex="-1">详细版 <a class="header-anchor" href="#详细版" aria-label="Permalink to &quot;详细版&quot;">​</a></h2><h3 id="三种渲染模式" tabindex="-1">三种渲染模式 <a class="header-anchor" href="#三种渲染模式" aria-label="Permalink to &quot;三种渲染模式&quot;">​</a></h3><p>Yumina 的前端渲染分三个层级，从简单到复杂：</p><h4 id="_1-默认模式-什么都不做" tabindex="-1">1. 默认模式：什么都不做 <a class="header-anchor" href="#_1-默认模式-什么都不做" aria-label="Permalink to &quot;1. 默认模式：什么都不做&quot;">​</a></h4><p>AI 的回复显示为普通 Markdown 文字。够用但不好看。适合刚开始搭建世界的时候先跑通逻辑。</p><h4 id="_2-messagerenderer-改造消息外观" tabindex="-1">2. messageRenderer：改造消息外观 <a class="header-anchor" href="#_2-messagerenderer-改造消息外观" aria-label="Permalink to &quot;2. messageRenderer：改造消息外观&quot;">​</a></h4><p>一段 TSX 代码，替换默认的文字渲染。每条 AI 回复都会经过它。</p><p>适合做：</p><ul><li>带角色头像和名字的气泡对话</li><li>视觉小说风格（背景图 + 立绘 + 对话框）</li><li>带颜色标记的战斗日志</li><li>在消息上方/下方显示状态面板</li></ul><p>在哪设置：编辑器 → <strong>消息渲染器（Message Renderer）</strong> 区域 → 选 <strong>自定义 TSX（Custom TSX）</strong> → 粘贴代码</p><h4 id="_3-customcomponents-独立的-ui-面板" tabindex="-1">3. customComponents：独立的 UI 面板 <a class="header-anchor" href="#_3-customcomponents-独立的-ui-面板" aria-label="Permalink to &quot;3. customComponents：独立的 UI 面板&quot;">​</a></h4><p>一个或多个 TSX 组件，作为额外的面板显示。不替换消息，而是在消息旁边或上方出现。</p><p>适合做：</p><ul><li>角色创建界面</li><li>游戏侧边栏（状态、背包、地图）</li><li>全屏接管（设置 <code>fullScreenComponent: true</code> 后，customComponents 占据整个屏幕，聊天隐藏）</li></ul><p>在哪设置：<strong>Studio</strong> → <strong>Code View</strong> 面板 → 点 <strong>+</strong> 添加组件 → 写代码或让 AI 写（需要先点 <strong>进入 Studio（Enter Studio）</strong>）</p><h4 id="messagerenderer-vs-customcomponents-怎么选" tabindex="-1">messageRenderer vs customComponents 怎么选 <a class="header-anchor" href="#messagerenderer-vs-customcomponents-怎么选" aria-label="Permalink to &quot;messageRenderer vs customComponents 怎么选&quot;">​</a></h4><table tabindex="0"><thead><tr><th></th><th>messageRenderer</th><th>customComponents</th></tr></thead><tbody><tr><td>数量</td><td>只能有一个</td><td>可以有多个</td></tr><tr><td>位置</td><td>替换消息渲染</td><td>消息旁边/上方，或全屏</td></tr><tr><td>适合</td><td>改消息的外观</td><td>做独立的游戏 UI</td></tr><tr><td>编辑</td><td>编辑器或 Studio</td><td>只能在 Studio</td></tr></tbody></table><p>大多数世界只用 messageRenderer 就够了。需要全屏游戏界面的时候才用 customComponents。</p><hr><h3 id="用-studio-ai-生成界面" tabindex="-1">用 Studio AI 生成界面 <a class="header-anchor" href="#用-studio-ai-生成界面" aria-label="Permalink to &quot;用 Studio AI 生成界面&quot;">​</a></h3><p>这是最推荐的方式。不用写代码，跟 AI 聊天就行。</p><h4 id="进入-studio" tabindex="-1">进入 Studio <a class="header-anchor" href="#进入-studio" aria-label="Permalink to &quot;进入 Studio&quot;">​</a></h4><p>编辑器顶部 → 点 <strong>进入 Studio（Enter Studio）</strong></p><p>Studio 有几个面板：</p><table tabindex="0"><thead><tr><th>面板</th><th>干什么</th></tr></thead><tbody><tr><td><strong>AI Assistant</strong></td><td>跟 AI 聊天，让它帮你生成/修改代码</td></tr><tr><td><strong>Canvas</strong></td><td>实时预览你的界面效果</td></tr><tr><td><strong>Code View</strong></td><td>查看和编辑代码（messageRenderer + customComponents）</td></tr><tr><td><strong>Playtest</strong></td><td>内嵌聊天，测试游戏</td></tr></tbody></table><h4 id="怎么跟-studio-ai-说" tabindex="-1">怎么跟 Studio AI 说 <a class="header-anchor" href="#怎么跟-studio-ai-说" aria-label="Permalink to &quot;怎么跟 Studio AI 说&quot;">​</a></h4><p>直接用中文描述你想要的效果就行。越具体越好。</p><p><strong>示例 1 — RPG 状态面板：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我改一下消息显示方式，给我的奇幻RPG世界加一个状态面板。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我想要的效果：</span></span>
<span class="line"><span>1. 每条消息上方有一个暗紫色的面板，带淡紫色发光边框，圆角</span></span>
<span class="line"><span>2. 面板里横排显示三样东西：</span></span>
<span class="line"><span>   - 红色血条，显示当前HP（hp变量）和最大HP（max_hp变量）</span></span>
<span class="line"><span>   - 蓝色魔力条，显示当前MP（mp变量）和最大MP（max_mp变量）</span></span>
<span class="line"><span>   - 金色的金币数量，读 gold 变量，旁边带个金币图标</span></span>
<span class="line"><span>3. 面板下面正常显示消息文字</span></span>
<span class="line"><span>4. 整体暗色奇幻风格，面板不要太高</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我的变量：</span></span>
<span class="line"><span>- hp — 当前生命值，数字</span></span>
<span class="line"><span>- max_hp — 最大生命值，数字</span></span>
<span class="line"><span>- mp — 当前魔力，数字</span></span>
<span class="line"><span>- max_mp — 最大魔力，数字</span></span>
<span class="line"><span>- gold — 金币，数字</span></span>
<span class="line"><span>- location — 当前位置，文字</span></span></code></pre></div><p>Studio AI 会生成代码并弹出审核卡片。看一眼 Canvas 预览效果，满意就点 <strong>Approve</strong>，不满意就继续说具体的修改要求。</p><p><strong>示例 2 — 视觉小说风格：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我做一个视觉小说/galgame风格的消息显示。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我想要的效果：</span></span>
<span class="line"><span>1. 整个区域像一个游戏场景画面，宽高比大概 16:9</span></span>
<span class="line"><span>   - 背景图从 currentScene 变量读（存的是图片链接）</span></span>
<span class="line"><span>   - 没有背景图的时候显示深蓝色渐变</span></span>
<span class="line"><span>2. 画面中央显示角色的立绘图片</span></span>
<span class="line"><span>   - 图片从 characterPortrait 变量读（也是图片链接）</span></span>
<span class="line"><span>   - 大一点，居中显示</span></span>
<span class="line"><span>3. 底部是一个半透明的黑色对话框</span></span>
<span class="line"><span>   - 说话人名字从 characterName 变量读，名字用樱花粉色</span></span>
<span class="line"><span>   - 对话内容就是AI回复的文字</span></span>
<span class="line"><span>4. 如果文字里有 *星号包裹的内容*，那是动作描述，用灰色斜体显示在对话框上面</span></span>
<span class="line"><span>5. 右上角小字显示好感度（affection变量），低好感红色，高好感粉色</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我的变量：</span></span>
<span class="line"><span>- currentScene — 背景图链接，文字</span></span>
<span class="line"><span>- characterPortrait — 角色立绘链接，文字</span></span>
<span class="line"><span>- characterName — 角色名字，文字</span></span>
<span class="line"><span>- affection — 好感度，数字，0到100</span></span></code></pre></div><hr><h3 id="用外部-ai-生成界面" tabindex="-1">用外部 AI 生成界面 <a class="header-anchor" href="#用外部-ai-生成界面" aria-label="Permalink to &quot;用外部 AI 生成界面&quot;">​</a></h3><p>如果你更习惯用 Claude、ChatGPT 或其他 AI，也完全没问题。关键是告诉它 Yumina 的环境信息。</p><h4 id="给外部-ai-怎么说" tabindex="-1">给外部 AI 怎么说 <a class="header-anchor" href="#给外部-ai-怎么说" aria-label="Permalink to &quot;给外部 AI 怎么说&quot;">​</a></h4><p>外部 AI（Claude、ChatGPT、DeepSeek 等）不了解 Yumina，所以除了描述你想要的效果，还需要告诉它一些技术信息。格式很简单——先用大白话描述效果，末尾附上技术信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我在用一个叫 Yumina 的AI互动平台做世界，帮我写一段代码改变消息显示方式。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我想要的效果：</span></span>
<span class="line"><span>[用大白话描述你想要什么，颜色、布局、风格、读哪些变量]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>我的变量：</span></span>
<span class="line"><span>[列出你的变量，写明每个是什么、存什么值]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Yumina 技术信息（写代码时请遵守）：</span></span>
<span class="line"><span>- 代码格式 TSX，用 export default function Renderer({ content, renderMarkdown }) { ... } 导出</span></span>
<span class="line"><span>- useYumina() 可以读变量，比如 useYumina().variables.health</span></span>
<span class="line"><span>- 内置 YUI 组件库（不用 import 直接用）：</span></span>
<span class="line"><span>  YUI.Scene（背景）、YUI.Sprite（立绘）、YUI.DialogueBox（对话框）、</span></span>
<span class="line"><span>  YUI.StatBar（血条）、YUI.StatCard（属性卡）、YUI.Panel（面板容器）、</span></span>
<span class="line"><span>  YUI.Tabs（标签页）、YUI.ItemGrid（物品格子）、YUI.ChoiceButtons（选择按钮）、</span></span>
<span class="line"><span>  YUI.ActionButton（动作按钮）、YUI.Badge（标签）、YUI.Fullscreen（全屏）</span></span>
<span class="line"><span>- 内置 Icons 图标库（不用 import），比如 Icons.Heart, Icons.Sword, Icons.Coins</span></span>
<span class="line"><span>- renderMarkdown(content) 把文字变成 HTML</span></span>
<span class="line"><span>- 支持 Tailwind CSS 和 React hooks</span></span></code></pre></div><p>AI 给你代码后：</p><ol><li>如果是 <strong>messageRenderer</strong> → 编辑器 → Message Renderer → Custom TSX → 粘贴</li><li>如果是 <strong>customComponent</strong> → Studio → Code View → 点 + → 粘贴</li></ol><p>底部显示 <strong>编译状态：OK（Compile Status: OK）</strong> 就成功了。报错就把错误信息发回给 AI 让它修。</p><hr><h3 id="yui-组件库速览" tabindex="-1">YUI 组件库速览 <a class="header-anchor" href="#yui-组件库速览" aria-label="Permalink to &quot;YUI 组件库速览&quot;">​</a></h3><p>TSX 代码里可以直接用这些预制组件，不需要 import：</p><table tabindex="0"><thead><tr><th>组件</th><th>用途</th><th>常用 props</th></tr></thead><tbody><tr><td><code>YUI.Scene</code></td><td>背景场景</td><td><code>bg</code>(背景图URL), <code>transition</code></td></tr><tr><td><code>YUI.Sprite</code></td><td>角色立绘</td><td><code>src</code>(图片URL), <code>position</code>(left/center/right), <code>size</code></td></tr><tr><td><code>YUI.DialogueBox</code></td><td>对话框</td><td><code>speaker</code>(说话人), <code>speakerColor</code>, <code>variant</code>(default/thought/narration)</td></tr><tr><td><code>YUI.ChoiceButtons</code></td><td>选择按钮</td><td><code>choices</code>(选项数组), <code>onChoice</code>, <code>layout</code>(vertical/horizontal/grid)</td></tr><tr><td><code>YUI.StatBar</code></td><td>状态条</td><td><code>label</code>, <code>value</code>, <code>max</code>, <code>color</code></td></tr><tr><td><code>YUI.StatCard</code></td><td>属性卡片</td><td><code>label</code>, <code>value</code>, <code>icon</code></td></tr><tr><td><code>YUI.Panel</code></td><td>容器面板</td><td><code>title</code>, <code>children</code></td></tr><tr><td><code>YUI.Tabs</code></td><td>标签页切换</td><td><code>tabs</code>(标签数组), <code>activeTab</code>, <code>onTabChange</code></td></tr><tr><td><code>YUI.ItemGrid</code></td><td>物品格子</td><td><code>items</code>(物品数组), <code>columns</code>, <code>emptySlots</code></td></tr><tr><td><code>YUI.ActionButton</code></td><td>动作按钮</td><td><code>label</code>, <code>icon</code>, <code>onClick</code></td></tr><tr><td><code>YUI.Badge</code></td><td>小标签</td><td><code>children</code>, <code>variant</code></td></tr><tr><td><code>YUI.Fullscreen</code></td><td>全屏切换</td><td><code>children</code></td></tr></tbody></table><p>这些组件默认暗色主题，有平滑动画，开箱即用。你（或者帮你写代码的 AI）可以通过 <code>className</code> prop 用 Tailwind CSS 进一步自定义样式。</p><hr><h3 id="useyumina-—-读写游戏状态" tabindex="-1">useYumina() — 读写游戏状态 <a class="header-anchor" href="#useyumina-—-读写游戏状态" aria-label="Permalink to &quot;useYumina() — 读写游戏状态&quot;">​</a></h3><p>TSX 代码里用 <code>useYumina()</code> hook 可以访问游戏的一切：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const api = useYumina();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>api.variables          // 所有变量的当前值，比如 api.variables.health</span></span>
<span class="line"><span>api.sendMessage(text)  // 以玩家身份发送一条消息</span></span>
<span class="line"><span>api.setVariable(id, value)  // 直接设置一个变量的值</span></span>
<span class="line"><span>api.executeAction(id)  // 触发一个规则动作</span></span>
<span class="line"><span>api.isStreaming        // AI 是否正在生成中</span></span>
<span class="line"><span>api.streamingContent   // AI 正在生成的内容（实时）</span></span>
<span class="line"><span>api.resolveAssetUrl(ref)  // 把素材引用转成真实 URL</span></span>
<span class="line"><span>api.playAudio(trackId)    // 播放音频</span></span>
<span class="line"><span>api.stopAudio(trackId)    // 停止音频</span></span></code></pre></div><p>你不需要记住这些——让 AI 帮你写代码的时候它会自动用上。这里只是列出来做参考。</p><hr><h2 id="实用例子" tabindex="-1">实用例子 <a class="header-anchor" href="#实用例子" aria-label="Permalink to &quot;实用例子&quot;">​</a></h2><p>每个例子都给出完整的 prompt，你可以直接复制发给 Studio AI 或外部 AI 使用。</p><hr><h3 id="例子-1-恐怖游戏状态栏-messagerenderer" tabindex="-1">例子 1：恐怖游戏状态栏（messageRenderer） <a class="header-anchor" href="#例子-1-恐怖游戏状态栏-messagerenderer" aria-label="Permalink to &quot;例子 1：恐怖游戏状态栏（messageRenderer）&quot;">​</a></h3><p><strong>效果</strong>：每条消息上方显示暗色恐怖风格的 HP/体力/天数面板。</p><p><strong>复制这段发给 Studio AI 或外部 AI：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我改消息显示方式，做一个恐怖生存游戏的状态面板。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>效果：</span></span>
<span class="line"><span>1. 每条消息上面有一个暗色状态栏，深灰偏黑背景，带暗红色细边框，圆角</span></span>
<span class="line"><span>2. 状态栏里从左到右显示：</span></span>
<span class="line"><span>   - 红色的HP血条（读 health 变量，满血 100）</span></span>
<span class="line"><span>   - 绿色的体力条（读 energy 变量，满体力 100）</span></span>
<span class="line"><span>   - 右边用琥珀色文字显示&quot;第X天 · 夜晚&quot;（读 day 和 phase 变量）</span></span>
<span class="line"><span>   - 如果 is_armed 是 true，最右边加一个白色小剑图标</span></span>
<span class="line"><span>3. 状态栏下面正常显示消息文字</span></span>
<span class="line"><span>4. 风格要压抑、低饱和度，末日恐怖的感觉</span></span>
<span class="line"><span></span></span>
<span class="line"><span>变量：health（生命值，0-100），energy（体力，0-100），day（天数），phase（&quot;night&quot;或&quot;day&quot;），is_armed（是否武装，是/否）</span></span></code></pre></div><p>如果用外部 AI，在末尾加上这段技术信息：</p><blockquote><p>Yumina 平台，TSX 格式，export default function Renderer({ content, renderMarkdown })，useYumina().variables 读变量，YUI.StatBar 做血条，Icons.Sword 做图标，renderMarkdown(content) 渲染文字，支持 Tailwind CSS。</p></blockquote><hr><h3 id="例子-2-视觉小说风格-messagerenderer" tabindex="-1">例子 2：视觉小说风格（messageRenderer） <a class="header-anchor" href="#例子-2-视觉小说风格-messagerenderer" aria-label="Permalink to &quot;例子 2：视觉小说风格（messageRenderer）&quot;">​</a></h3><p><strong>效果</strong>：全屏场景背景 + 角色立绘 + 底部半透明对话框。</p><p><strong>复制这段发给 Studio AI 或外部 AI：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我做一个视觉小说/galgame风格的消息显示。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>效果：</span></span>
<span class="line"><span>1. 整个区域像游戏场景画面，16:9比例</span></span>
<span class="line"><span>   - 背景图从 currentScene 变量读（图片链接），没图的时候深蓝渐变</span></span>
<span class="line"><span>2. 画面中间显示角色立绘，从 characterPortrait 变量读，大图居中</span></span>
<span class="line"><span>3. 底部半透明黑色对话框：</span></span>
<span class="line"><span>   - 说话人名字从 characterName 变量读，名字用樱花粉色</span></span>
<span class="line"><span>   - 对话内容就是AI的回复文字</span></span>
<span class="line"><span>4. *星号包裹的文字* 是动作描述，灰色斜体显示在对话框上面</span></span>
<span class="line"><span>5. 右上角小字显示好感度 ♥（读 affection 变量），低好感红色、中间白色、高好感粉色</span></span>
<span class="line"><span></span></span>
<span class="line"><span>变量：currentScene（背景图链接），characterPortrait（角色立绘链接），characterName（角色名），affection（好感度，0-100）</span></span></code></pre></div><p>如果用外部 AI，在末尾加上这段技术信息：</p><blockquote><p>Yumina 平台，TSX 格式，export default function Renderer({ content, renderMarkdown })，useYumina().variables 读变量，YUI.Scene 做背景、YUI.Sprite 做立绘、YUI.DialogueBox 做对话框，renderMarkdown(content) 渲染文字，支持 Tailwind CSS。</p></blockquote><hr><h3 id="例子-3-游戏侧边栏-customcomponent" tabindex="-1">例子 3：游戏侧边栏（customComponent） <a class="header-anchor" href="#例子-3-游戏侧边栏-customcomponent" aria-label="Permalink to &quot;例子 3：游戏侧边栏（customComponent）&quot;">​</a></h3><p><strong>效果</strong>：聊天旁边的侧边栏，显示角色信息 + 属性 + 背包。</p><p><strong>复制这段发给 Studio AI 或外部 AI：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我做一个游戏侧边栏（作为 customComponent，不是 messageRenderer）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>效果：</span></span>
<span class="line"><span>1. 深灰色背景面板，圆角</span></span>
<span class="line"><span>2. 顶部是角色信息：</span></span>
<span class="line"><span>   - 左边圆形头像（从 playerAvatar 变量读图片链接），紫色边框</span></span>
<span class="line"><span>   - 右边是角色名（playerName 变量）和等级&quot;Lv.X&quot;（level 变量），等级用紫色</span></span>
<span class="line"><span>3. 中间是属性区域，标题&quot;属性&quot;：</span></span>
<span class="line"><span>   - 红色HP血条，读 hp 和 max_hp 变量</span></span>
<span class="line"><span>   - 蓝色MP条，读 mp 和 max_mp 变量</span></span>
<span class="line"><span>   - 三个属性卡片横排：力量（strength，剑图标）、防御（defense，盾图标）、速度（speed，闪电图标）</span></span>
<span class="line"><span>4. 底部是背包区域，标题&quot;背包&quot;：</span></span>
<span class="line"><span>   - 3列的物品格子，从 inventory 变量读（数组，每个物品有 name、icon、count）</span></span>
<span class="line"><span>   - 空格子显示灰色虚线框，总共9个格位</span></span>
<span class="line"><span></span></span>
<span class="line"><span>变量：playerAvatar（头像链接），playerName（角色名），level（等级），hp/max_hp（当前/最大生命），mp/max_mp（当前/最大魔力），strength/defense/speed（属性数字），inventory（背包数组）</span></span></code></pre></div><p>如果用外部 AI，在末尾加上这段技术信息：</p><blockquote><p>Yumina 平台，TSX 格式，export default function Component()，useYumina().variables 读变量，YUI.StatBar 做血条、YUI.StatCard 做属性卡、YUI.ItemGrid 做背包、YUI.Panel 做面板容器，Icons.Sword/Shield/Zap 等图标可用，支持 Tailwind CSS。</p></blockquote><div class="tip custom-block"><p class="custom-block-title">这些 prompt 可以直接用</p><p>上面三个 prompt 可以直接复制发给 Studio AI 或外部 AI。拿到代码后粘贴进去就行。觉得效果不对就继续跟 AI 聊，让它调整颜色、大小、布局。</p></div><div class="info custom-block"><p class="custom-block-title">技术细节</p><p>想深入了解 TSX 语法、Props 接口、编译环境等技术细节 → <a href="./08-message-renderer.html">自定义消息渲染器</a></p></div>`,87)])])}const m=n(p,[["render",o]]);export{h as __pageData,m as default};
